import styles from './Button.module.css'

export function Button({ as: Comp = 'button', variant = 'primary', size = 'md', className = '', ...props }) {
  const cls = [styles.button, styles[variant], styles[size], className].filter(Boolean).join(' ')
  // Если это <button>, оставляем type по умолчанию "button", чтобы не сабмитить формы.
  if (Comp === 'button' && props.type == null) {
    // eslint-disable-next-line no-param-reassign
    props.type = 'button'
  }
  return <Comp className={cls} {...props} />
}

import styles from './Card.module.css'

export function Card({ as: Comp = 'div', className = '', ...props }) {
  return <Comp className={[styles.card, className].filter(Boolean).join(' ')} {...props} />
}

import { useCallback, useEffect, useMemo, useState } from 'react'

const KEYS = {
  words: 'hsk_words_progress',
  grammar: 'hsk_grammar_progress',
  examResults: 'hsk_exam_results',
  streak: 'hsk_streak',
  examDate: 'hsk_exam_date',
  dailySessions: 'hsk_daily_sessions',
  settings: 'hsk_settings',
}

function safeParse(json, fallback) {
  try {
    return JSON.parse(json)
  } catch {
    return fallback
  }
}

function todayISO() {
  return new Date().toISOString().slice(0, 10)
}

export function useProgress() {
  const [tick, setTick] = useState(0)

  const read = useCallback((key, fallback) => {
    const raw = localStorage.getItem(key)
    if (raw == null) return fallback
    return safeParse(raw, fallback)
  }, [])

  const write = useCallback((key, value) => {
    localStorage.setItem(key, JSON.stringify(value))
    setTick((t) => t + 1)
  }, [])

  // Ensure defaults exist
  useEffect(() => {
    if (localStorage.getItem(KEYS.words) == null) write(KEYS.words, {})
    if (localStorage.getItem(KEYS.grammar) == null) write(KEYS.grammar, {})
    if (localStorage.getItem(KEYS.examResults) == null) write(KEYS.examResults, [])
    if (localStorage.getItem(KEYS.dailySessions) == null) write(KEYS.dailySessions, [])
    if (localStorage.getItem(KEYS.streak) == null) write(KEYS.streak, { last_date: null, count: 0 })
    if (localStorage.getItem(KEYS.examDate) == null) write(KEYS.examDate, '2025-05-16')
    if (localStorage.getItem(KEYS.settings) == null)
      write(KEYS.settings, { pinyinPosition: 'below' }) // 'above' | 'below'
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const wordsProgress = useMemo(() => read(KEYS.words, {}), [read, tick])
  const grammarProgress = useMemo(() => read(KEYS.grammar, {}), [read, tick])
  const examResults = useMemo(() => read(KEYS.examResults, []), [read, tick])
  const streak = useMemo(() => read(KEYS.streak, { last_date: null, count: 0 }), [read, tick])
  const examDate = useMemo(() => read(KEYS.examDate, '2025-05-16'), [read, tick])
  const dailySessions = useMemo(() => read(KEYS.dailySessions, []), [read, tick])
  const settings = useMemo(() => read(KEYS.settings, { pinyinPosition: 'below' }), [read, tick])

  const ensureTodaySession = useCallback(() => {
    const d = todayISO()
    const sessions = read(KEYS.dailySessions, [])
    if (!sessions.includes(d)) write(KEYS.dailySessions, [...sessions, d])

    const s = read(KEYS.streak, { last_date: null, count: 0 })
    if (s.last_date === d) return

    const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().slice(0, 10)
    const next =
      s.last_date === yesterday
        ? { last_date: d, count: Math.max(1, (s.count || 0) + 1) }
        : { last_date: d, count: 1 }
    write(KEYS.streak, next)
  }, [read, write])

  const setExamDate = useCallback((isoDate) => write(KEYS.examDate, isoDate), [write])
  const setSettings = useCallback((next) => write(KEYS.settings, next), [write])

  const setWordProgress = useCallback(
    (wordId, patch) => {
      const all = read(KEYS.words, {})
      const prev = all[String(wordId)] ?? { status: 'new', correctStreak: 0, wrongCount: 0, lastSeen: null }
      const next = { ...prev, ...patch }
      all[String(wordId)] = next
      write(KEYS.words, all)
      ensureTodaySession()
    },
    [ensureTodaySession, read, write],
  )

  const setGrammarDone = useCallback(
    (grammarId, done) => {
      const all = read(KEYS.grammar, {})
      all[String(grammarId)] = Boolean(done)
      write(KEYS.grammar, all)
      ensureTodaySession()
    },
    [ensureTodaySession, read, write],
  )

  const addExamResult = useCallback(
    (result) => {
      const prev = read(KEYS.examResults, [])
      const next = Array.isArray(prev) ? [...prev, result] : [result]
      write(KEYS.examResults, next)
      ensureTodaySession()
    },
    [ensureTodaySession, read, write],
  )

  return {
    keys: KEYS,
    wordsProgress,
    grammarProgress,
    examResults,
    streak,
    examDate,
    dailySessions,
    settings,
    setExamDate,
    setSettings,
    setWordProgress,
    setGrammarDone,
    addExamResult,
    ensureTodaySession,
  }
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'

function pickVoice(voices, langPrefix) {
  if (!voices || voices.length === 0) return null
  const byLang = voices.filter((v) => (v.lang || '').toLowerCase().startsWith(langPrefix.toLowerCase()))
  return byLang[0] ?? voices[0] ?? null
}

export function useTTS({ defaultLang = 'zh-CN' } = {}) {
  const [available, setAvailable] = useState(() => typeof window !== 'undefined' && 'speechSynthesis' in window)
  const [voices, setVoices] = useState([])
  const [voiceName, setVoiceName] = useState('')
  const synthRef = useRef(null)

  useEffect(() => {
    if (!available) return
    synthRef.current = window.speechSynthesis

    const load = () => {
      const list = synthRef.current?.getVoices?.() ?? []
      setVoices(list)
      const picked = list.find((v) => v.name === voiceName) ?? pickVoice(list, defaultLang) ?? null
      if (picked && picked.name !== voiceName) setVoiceName(picked.name)
    }

    load()
    synthRef.current.onvoiceschanged = load
    return () => {
      if (synthRef.current) synthRef.current.onvoiceschanged = null
    }
  }, [available, defaultLang, voiceName])

  const voice = useMemo(() => voices.find((v) => v.name === voiceName) ?? null, [voices, voiceName])

  const speak = useCallback(
    (text, { lang = defaultLang, rate = 1.0, pitch = 1.0 } = {}) => {
      if (!available) return false
      if (!text || !String(text).trim()) return false
      const u = new SpeechSynthesisUtterance(String(text))
      u.lang = lang
      u.rate = rate
      u.pitch = pitch
      if (voice) u.voice = voice
      window.speechSynthesis.cancel()
      window.speechSynthesis.speak(u)
      return true
    },
    [available, defaultLang, voice],
  )

  const cancel = useCallback(() => {
    if (!available) return
    window.speechSynthesis.cancel()
  }, [available])

  return {
    available,
    voices,
    voiceName,
    setVoiceName,
    speak,
    cancel,
  }
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'

export function useTimer({ initialSeconds = 0, autoStart = false } = {}) {
  const [secondsLeft, setSecondsLeft] = useState(initialSeconds)
  const [running, setRunning] = useState(autoStart)
  const intervalRef = useRef(null)

  const stop = useCallback(() => setRunning(false), [])
  const start = useCallback(() => setRunning(true), [])
  const reset = useCallback((nextSeconds = initialSeconds) => {
    setSecondsLeft(nextSeconds)
    setRunning(false)
  }, [initialSeconds])

  useEffect(() => {
    if (!running) {
      if (intervalRef.current) clearInterval(intervalRef.current)
      intervalRef.current = null
      return
    }
    intervalRef.current = setInterval(() => {
      setSecondsLeft((s) => (s > 0 ? s - 1 : 0))
    }, 1000)
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current)
      intervalRef.current = null
    }
  }, [running])

  useEffect(() => {
    if (secondsLeft === 0) setRunning(false)
  }, [secondsLeft])

  const mmss = useMemo(() => {
    const m = Math.floor(secondsLeft / 60)
    const s = secondsLeft % 60
    return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`
  }, [secondsLeft])

  return { secondsLeft, mmss, running, start, stop, reset, setSecondsLeft }
}

import { useEffect, useMemo, useState } from 'react'
import grammarData from '../../data/grammar.json'
import extra from '../../data/grammar.extra.json'
import { Card } from '../../components/shared/Card'
import { Button } from '../../components/shared/Button'
import { TTSButton } from '../../components/shared/TTSButton'
import { useProgress } from '../../hooks/useProgress'
import { useTTS } from '../../hooks/useTTS'
import styles from './GrammarPage.module.css'

function clamp(n, a, b) {
  return Math.max(a, Math.min(b, n))
}

function splitByBlanks(sentence) {
  return String(sentence).split('___')
}

export function GrammarPage() {
  return <GrammarPageImpl />
}

function GrammarPageImpl() {
  const { grammarProgress, setGrammarDone, ensureTodaySession } = useProgress()
  const { available: ttsAvailable, speak } = useTTS()

  const [selectedId, setSelectedId] = useState(() => grammarData[0]?.id ?? 1)
  const [exerciseIdx, setExerciseIdx] = useState(0)

  useEffect(() => {
    ensureTodaySession()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const doneCount = useMemo(() => Object.values(grammarProgress ?? {}).filter(Boolean).length, [grammarProgress])
  const extraById = useMemo(() => {
    const m = new Map()
    for (const e of extra ?? []) m.set(e.id, e.exercises ?? [])
    return m
  }, [])

  const selected = useMemo(() => {
    const base = grammarData.find((g) => g.id === selectedId) ?? grammarData[0]
    if (!base) return base
    const more = extraById.get(base.id) ?? []
    return { ...base, exercises: [...(base.exercises ?? []), ...more] }
  }, [extraById, selectedId])
  const isDone = Boolean(grammarProgress?.[String(selected?.id)])

  useEffect(() => {
    setExerciseIdx(0)
  }, [selectedId])

  const exercise = selected?.exercises?.[exerciseIdx] ?? null

  function speakZh(text, rate = 1.0) {
    speak(text, { lang: 'zh-CN', rate })
  }

  return (
    <div className={styles.layout}>
      <Card className={styles.sidebar}>
        <div className={styles.sideTop}>
          <div className={styles.sideTitle}>Грамматика</div>
          <div className={styles.sideMeta}>
            Пройдено: <b>{doneCount}</b> / <b>{grammarData.length}</b>
          </div>
        </div>

        <div className={styles.list} role="list">
          {grammarData.map((g) => {
            const done = Boolean(grammarProgress?.[String(g.id)])
            const active = g.id === selectedId
            return (
              <button
                key={g.id}
                type="button"
                className={[styles.item, active ? styles.itemActive : ''].filter(Boolean).join(' ')}
                onClick={() => setSelectedId(g.id)}
              >
                <span className={[styles.dot, done ? styles.dotDone : styles.dotTodo].join(' ')} aria-hidden="true" />
                <span className={styles.itemMain}>
                  <span className={styles.pattern}>{g.pattern}</span>
                  <span className={styles.name}>{g.name}</span>
                </span>
              </button>
            )
          })}
        </div>
      </Card>

      <div className={styles.content}>
        {!selected ? null : (
          <>
            <Card className={styles.header}>
              <div className={styles.hRow}>
                <div>
                  <div className={styles.hPattern}>{selected.pattern}</div>
                  <div className={styles.hName}>{selected.name}</div>
                </div>
                <div className={styles.hActions}>
                  <Button type="button" variant={isDone ? 'good' : 'primary'} onClick={() => setGrammarDone(selected.id, !isDone)}>
                    {isDone ? 'Пройдено' : 'Отметить пройдено'}
                  </Button>
                </div>
              </div>

              <div className={styles.expl}>{selected.explanation}</div>

              <div className={styles.examples}>
                {selected.examples?.map((ex, i) => (
                  <div key={i} className={styles.example}>
                    <div className={styles.exZhRow}>
                      <div className={styles.exZh}>{ex.zh}</div>
                      <TTSButton onSpeak={() => speakZh(ex.zh)} disabled={!ttsAvailable} />
                    </div>
                    <div className="pinyin">{ex.pinyin}</div>
                    <div className={styles.exRu}>{ex.ru}</div>
                  </div>
                ))}
              </div>
            </Card>

            <Card className={styles.exerciseCard}>
              <div className={styles.exTop}>
                <div className={styles.exTitle}>
                  Упражнение {exerciseIdx + 1} / {selected.exercises?.length ?? 0}
                </div>
                <div className={styles.exNav}>
                  <Button type="button" size="sm" variant="ghost" onClick={() => setExerciseIdx((i) => clamp(i - 1, 0, selected.exercises.length - 1))}>
                    Назад
                  </Button>
                  <Button type="button" size="sm" variant="ghost" onClick={() => setExerciseIdx((i) => clamp(i + 1, 0, selected.exercises.length - 1))}>
                    Далее
                  </Button>
                </div>
              </div>

              {!exercise ? (
                <div className={styles.exEmpty}>Нет упражнений.</div>
              ) : exercise.type === 'fill_blank' ? (
                <FillBlankExercise key={exerciseIdx} ex={exercise} onSpeak={speakZh} ttsAvailable={ttsAvailable} />
              ) : exercise.type === 'word_order' ? (
                <WordOrderExercise key={exerciseIdx} ex={exercise} onSpeak={speakZh} ttsAvailable={ttsAvailable} />
              ) : exercise.type === 'translate' ? (
                <TranslateExercise key={exerciseIdx} ex={exercise} />
              ) : (
                <div className={styles.exEmpty}>Неизвестный тип упражнения: {exercise.type}</div>
              )}
            </Card>
          </>
        )}
      </div>
    </div>
  )
}

function FillBlankExercise({ ex, onSpeak, ttsAvailable }) {
  const parts = splitByBlanks(ex.sentence_zh)
  const blanks = ex.blanks ?? []
  const [inputs, setInputs] = useState(() => blanks.map(() => ''))
  const [checked, setChecked] = useState(null) // null | { ok, expected }

  const sentencePreview = useMemo(() => {
    let out = ''
    for (let i = 0; i < parts.length; i++) {
      out += parts[i]
      if (i < blanks.length) out += inputs[i] || '＿'
    }
    return out
  }, [blanks.length, inputs, parts])

  function check() {
    const ok = blanks.every((b, i) => String(inputs[i]).trim() === String(b).trim())
    setChecked({ ok })
  }

  function reset() {
    setInputs(blanks.map(() => ''))
    setChecked(null)
  }

  return (
    <div className={styles.exBody}>
      <div className={styles.exType}>Заполни пропуски</div>

      <div className={styles.zhRow}>
        <div className={styles.zhSentence}>
          {parts.map((p, i) => (
            <span key={i}>
              {p}
              {i < blanks.length ? (
                <input
                  className={styles.blank}
                  value={inputs[i]}
                  onChange={(e) => {
                    const v = e.target.value
                    setInputs((prev) => prev.map((x, j) => (j === i ? v : x)))
                  }}
                  placeholder="___"
                  disabled={checked?.ok === true}
                />
              ) : null}
            </span>
          ))}
        </div>
        <TTSButton onSpeak={() => onSpeak(sentencePreview)} disabled={!ttsAvailable} />
      </div>

      <div className={styles.hints}>
        {blanks.map((b, i) => (
          <span key={i} className={styles.chip}>
            {b}
          </span>
        ))}
      </div>

      {checked ? (
        <div className={checked.ok ? styles.feedbackOk : styles.feedbackBad}>
          {checked.ok ? 'Правильно.' : 'Есть ошибки — попробуйте ещё раз.'}
        </div>
      ) : null}

      <div className={styles.actions}>
        <Button type="button" variant="primary" onClick={check} disabled={inputs.some((x) => !String(x).trim())}>
          Проверить
        </Button>
        <Button type="button" variant="ghost" onClick={reset}>
          Сброс
        </Button>
      </div>
    </div>
  )
}

function WordOrderExercise({ ex, onSpeak, ttsAvailable }) {
  const [picked, setPicked] = useState([])
  const [remaining, setRemaining] = useState(() => ex.words ?? [])
  const [checked, setChecked] = useState(null) // null | { ok }

  const sentence = picked.join('')

  function pickWord(w, idx) {
    if (checked) return
    setPicked((p) => [...p, w])
    setRemaining((r) => r.filter((_, i) => i !== idx))
  }

  function undoWord(w, idx) {
    if (checked) return
    setRemaining((r) => {
      const next = [...r]
      next.splice(0, 0, w)
      return next
    })
    setPicked((p) => p.filter((_, i) => i !== idx))
  }

  function reset() {
    setPicked([])
    setRemaining(ex.words ?? [])
    setChecked(null)
  }

  function check() {
    const ok = sentence === ex.answer
    setChecked({ ok })
  }

  return (
    <div className={styles.exBody}>
      <div className={styles.exType}>Составь предложение</div>

      <div className={styles.zhRow}>
        <div className={styles.builder}>
          {picked.length === 0 ? <span className={styles.builderHint}>Нажимайте слова ниже, чтобы собрать предложение</span> : null}
          {picked.map((w, i) => (
            <button key={`${w}-${i}`} type="button" className={styles.chipBtnPicked} onClick={() => undoWord(w, i)}>
              {w}
            </button>
          ))}
        </div>
        <TTSButton onSpeak={() => onSpeak(sentence || ex.answer)} disabled={!ttsAvailable} />
      </div>

      <div className={styles.hints}>
        {remaining.map((w, i) => (
          <button key={`${w}-${i}`} type="button" className={styles.chipBtn} onClick={() => pickWord(w, i)}>
            {w}
          </button>
        ))}
      </div>

      {checked ? (
        <div className={checked.ok ? styles.feedbackOk : styles.feedbackBad}>
          {checked.ok ? (
            'Правильно.'
          ) : (
            <>
              Неправильно. Ответ: <b>{ex.answer}</b>
            </>
          )}
        </div>
      ) : null}

      <div className={styles.actions}>
        <Button type="button" variant="primary" onClick={check} disabled={picked.length === 0}>
          Проверить
        </Button>
        <Button type="button" variant="ghost" onClick={reset}>
          Сброс
        </Button>
      </div>
    </div>
  )
}

function TranslateExercise({ ex }) {
  const [text, setText] = useState('')
  const [revealed, setRevealed] = useState(false)

  return (
    <div className={styles.exBody}>
      <div className={styles.exType}>Переведи на китайский (самопроверка)</div>

      <div className={styles.translateRu}>{ex.ru}</div>
      <div className={styles.hints}>
        {(ex.hint_words ?? []).map((w, i) => (
          <span key={i} className={styles.chip}>
            {w}
          </span>
        ))}
      </div>

      <textarea
        className={styles.textarea}
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Напишите вариант по-китайски…"
        rows={3}
      />

      <div className={styles.actions}>
        <Button type="button" variant="primary" onClick={() => setRevealed(true)} disabled={!text.trim()}>
          Я написал(а)
        </Button>
        <Button type="button" variant="ghost" onClick={() => { setText(''); setRevealed(false) }}>
          Очистить
        </Button>
      </div>

      {revealed ? (
        <div className={styles.selfCheck}>
          <div className={styles.selfTitle}>Самопроверка</div>
          <div className={styles.selfHint}>
            В данных для этого типа упражнения нет «единственного правильного ответа», поэтому ориентируйтесь на подсказки и конструкцию урока.
          </div>
        </div>
      ) : null}
    </div>
  )
}

import { useEffect, useMemo, useState } from 'react'
import data from '../../data/listening.json'
import { Card } from '../../components/shared/Card'
import { Button } from '../../components/shared/Button'
import { TTSButton } from '../../components/shared/TTSButton'
import { useProgress } from '../../hooks/useProgress'
import { useTTS } from '../../hooks/useTTS'
import styles from './ListeningPage.module.css'

const TYPES = [
  { id: 'all', label: 'Все' },
  { id: 'true_false', label: 'Верно/Неверно' },
  { id: 'picture_description', label: 'Описание картинки' },
  { id: 'dialogue_question', label: 'Диалог + вопрос' },
]

const RATES = [
  { id: 0.7, label: '0.7×' },
  { id: 1.0, label: '1.0×' },
  { id: 1.2, label: '1.2×' },
]

export function ListeningPage() {
  return <ListeningPageImpl />
}

function shuffle(arr) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function ListeningPageImpl() {
  const { ensureTodaySession } = useProgress()
  const { available: ttsAvailable, speak, cancel } = useTTS()

  const [type, setType] = useState('all')
  const [rate, setRate] = useState(1.0)
  const [x3, setX3] = useState(true)
  const [order, setOrder] = useState('shuffle') // shuffle | in_order

  const [idx, setIdx] = useState(0)
  const [picked, setPicked] = useState(null) // null | { value, ok }
  const [replaysAfter, setReplaysAfter] = useState(0)

  useEffect(() => {
    ensureTodaySession()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const list = useMemo(() => {
    const base = type === 'all' ? data : data.filter((x) => x.type === type)
    return order === 'shuffle' ? shuffle(base) : base
  }, [order, type])

  const current = list[idx] ?? null

  useEffect(() => {
    setIdx(0)
    setPicked(null)
    setReplaysAfter(0)
    cancel()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type, order])

  useEffect(() => {
    setPicked(null)
    setReplaysAfter(0)
    cancel()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [idx])

  function speakCurrent() {
    if (!current) return
    const text =
      current.type === 'true_false'
        ? current.text_zh
        : current.type === 'picture_description'
          ? current.description_zh
          : current.dialogue_zh
    speak(String(text).replaceAll('\n', ' '), { lang: 'zh-CN', rate })
  }

  function next() {
    setPicked(null)
    setReplaysAfter(0)
    setIdx((i) => (i + 1 >= list.length ? 0 : i + 1))
  }

  function prev() {
    setPicked(null)
    setReplaysAfter(0)
    setIdx((i) => (i - 1 < 0 ? Math.max(0, list.length - 1) : i - 1))
  }

  function answerTF(val) {
    if (!current || picked) return
    const ok = Boolean(val) === Boolean(current.answer)
    setPicked({ value: val, ok })
  }

  function answerOption(i) {
    if (!current || picked) return
    const ok = Number(i) === Number(current.answer)
    setPicked({ value: i, ok })
  }

  // x3: после разбора автоматически проигрываем ещё раз (до 2 доп.повторов)
  useEffect(() => {
    if (!picked) return
    if (!x3) return
    if (!ttsAvailable) return
    if (replaysAfter >= 2) return
    const t = setTimeout(() => {
      speakCurrent()
      setReplaysAfter((n) => n + 1)
    }, 900)
    return () => clearTimeout(t)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [picked, x3, ttsAvailable])

  const title =
    current?.type === 'true_false'
      ? 'Верно / Неверно'
      : current?.type === 'picture_description'
        ? 'Описание картинки'
        : current?.type === 'dialogue_question'
          ? 'Диалог + вопрос'
          : ''

  return (
    <div className={styles.wrap}>
      <div className={styles.top}>
        <div className={styles.titleRow}>
          <div className={styles.title}>Аудирование</div>
          <div className={styles.meta}>
            Задание: <b>{Math.min(idx + 1, list.length)}</b> / <b>{list.length}</b>
          </div>
        </div>

        <Card className={styles.controls}>
          <div className={styles.row}>
            <label className={styles.label}>
              Тип
              <select className={styles.select} value={type} onChange={(e) => setType(e.target.value)}>
                {TYPES.map((t) => (
                  <option key={t.id} value={t.id}>
                    {t.label}
                  </option>
                ))}
              </select>
            </label>

            <label className={styles.label}>
              Порядок
              <select className={styles.select} value={order} onChange={(e) => setOrder(e.target.value)}>
                <option value="shuffle">Случайно</option>
                <option value="in_order">По порядку</option>
              </select>
            </label>

            <label className={styles.label}>
              Скорость
              <div className={styles.rateRow}>
                {RATES.map((r) => (
                  <Button
                    key={r.id}
                    type="button"
                    size="sm"
                    variant={rate === r.id ? 'primary' : 'ghost'}
                    onClick={() => setRate(r.id)}
                  >
                    {r.label}
                  </Button>
                ))}
              </div>
            </label>

            <label className={styles.label}>
              Режим ×3
              <div className={styles.toggleRow}>
                <input type="checkbox" checked={x3} onChange={(e) => setX3(e.target.checked)} />
                <span className={styles.toggleHint}>после разбора озвучить ещё раз</span>
              </div>
            </label>
          </div>
        </Card>
      </div>

      <Card className={styles.card}>
        {!current ? (
          <div className={styles.empty}>Нет заданий для выбранного фильтра.</div>
        ) : (
          <>
            <div className={styles.cardTop}>
              <div className={styles.badges}>
                <span className={styles.badge}>{title}</span>
                <span className={styles.badgeSoft}>текст скрыт до ответа</span>
              </div>
              <div className={styles.tts}>
                <TTSButton onSpeak={speakCurrent} disabled={!ttsAvailable} title="Прослушать" />
                <Button type="button" size="sm" variant="ghost" onClick={cancel}>
                  Стоп
                </Button>
              </div>
            </div>

            <div className={styles.qBlock}>
              {current.type === 'true_false' ? (
                <>
                  <div className={styles.qTitle}>Утверждение</div>
                  <div className={styles.qZh}>{current.statement_zh}</div>
                  <div className={styles.qRu}>{current.statement_ru}</div>

                  <div className={styles.options}>
                    <OptionButton
                      mainZh="对"
                      subRu="Верно"
                      chosen={picked?.value === true}
                      ok={picked ? Boolean(current.answer) === true : null}
                      bad={picked ? picked.value === true && !picked.ok : null}
                      disabled={Boolean(picked)}
                      onClick={() => answerTF(true)}
                    />
                    <OptionButton
                      mainZh="错"
                      subRu="Неверно"
                      chosen={picked?.value === false}
                      ok={picked ? Boolean(current.answer) === false : null}
                      bad={picked ? picked.value === false && !picked.ok : null}
                      disabled={Boolean(picked)}
                      onClick={() => answerTF(false)}
                    />
                  </div>
                </>
              ) : (
                <>
                  <div className={styles.qTitle}>Вопрос</div>
                  <div className={styles.qZh}>{current.question_zh}</div>
                  <div className={styles.qRu}>{current.question_ru}</div>

                  <div className={styles.options}>
                    {current.options_zh.map((zh, i) => (
                      <OptionButton
                        key={i}
                        prefix={`${String.fromCharCode(65 + i)}.`}
                        mainZh={zh}
                        subRu={current.options_ru?.[i]}
                        chosen={picked?.value === i}
                        ok={picked ? Number(current.answer) === i : null}
                        bad={picked ? picked.value === i && !picked.ok : null}
                        disabled={Boolean(picked)}
                        onClick={() => answerOption(i)}
                      />
                    ))}
                  </div>
                </>
              )}
            </div>

            {picked ? (
              <div className={picked.ok ? styles.feedbackOk : styles.feedbackBad}>
                {picked.ok ? 'Правильно.' : 'Неправильно.'}
                <div className={styles.feedbackMeta}>
                  Правильный ответ:{' '}
                  <b>
                    {current.type === 'true_false'
                      ? Boolean(current.answer)
                        ? 'Верно'
                        : 'Неверно'
                      : `${String.fromCharCode(65 + Number(current.answer))}. ${current.options_ru?.[Number(current.answer)] ?? ''}`}
                  </b>
                </div>
                <div className={styles.afterRow}>
                  <Button type="button" variant="ghost" size="sm" onClick={speakCurrent} disabled={!ttsAvailable}>
                    Прослушать ещё раз
                  </Button>
                  {x3 ? <span className={styles.afterHint}>автоповторы: {replaysAfter}/2</span> : null}
                </div>
              </div>
            ) : null}

            {picked ? (
              <div className={styles.textBlock}>
                <div className={styles.textTitle}>Текст</div>
                {current.type === 'true_false' ? (
                  <>
                    <div className={styles.textZh}>{current.text_zh}</div>
                    <div className="pinyin">{current.text_pinyin}</div>
                  </>
                ) : current.type === 'picture_description' ? (
                  <>
                    <div className={styles.textZh}>{current.description_zh}</div>
                    <div className="pinyin">{current.description_pinyin}</div>
                  </>
                ) : (
                  <>
                    <pre className={styles.dialogue}>{current.dialogue_zh}</pre>
                    <pre className={styles.dialoguePinyin}>{current.dialogue_pinyin}</pre>
                  </>
                )}
              </div>
            ) : null}

            <div className={styles.nav}>
              <Button type="button" variant="ghost" onClick={prev}>
                Назад
              </Button>
              <Button type="button" variant="primary" onClick={next}>
                Далее
              </Button>
            </div>
          </>
        )}
      </Card>
    </div>
  )
}

function OptionButton({ prefix, mainZh, subRu, chosen, ok, bad, disabled, onClick }) {
  const cls = [
    styles.option,
    chosen ? styles.optionChosen : '',
    ok ? styles.optionOk : '',
    bad ? styles.optionBad : '',
  ]
    .filter(Boolean)
    .join(' ')
  return (
    <button type="button" className={cls} disabled={disabled} onClick={onClick}>
      <div className={styles.optMainRow}>
        {prefix ? <span className={styles.optPrefix}>{prefix}</span> : null}
        <span className={styles.optZh}>{mainZh}</span>
      </div>
      {subRu ? <div className={styles.optSub}>{subRu}</div> : null}
    </button>
  )
}

import { useEffect, useMemo, useState } from 'react'
import listening from '../../data/listening.json'
import reading from '../../data/reading.json'
import writing from '../../data/writing.json'
import { Card } from '../../components/shared/Card'
import { Button } from '../../components/shared/Button'
import { TTSButton } from '../../components/shared/TTSButton'
import { useProgress } from '../../hooks/useProgress'
import { useTimer } from '../../hooks/useTimer'
import { useTTS } from '../../hooks/useTTS'
import styles from './MockExamPage.module.css'

const SECTION = {
  intro: 'intro',
  listening: 'listening',
  reading: 'reading',
  writing: 'writing',
  done: 'done',
}

function shuffle(arr) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

function todayISO() {
  return new Date().toISOString().slice(0, 10)
}

function pct(correct, total) {
  if (!total) return 0
  return Math.round((correct / total) * 100)
}

export function MockExamPage() {
  const { addExamResult, ensureTodaySession } = useProgress()
  const { available: ttsAvailable, speak, cancel } = useTTS()

  const [section, setSection] = useState(SECTION.intro)

  const [listeningItems, setListeningItems] = useState([])
  const [readingItems, setReadingItems] = useState([])
  const [writingItems, setWritingItems] = useState([])

  const [idx, setIdx] = useState(0)

  // answers maps by section: index -> answer
  const [ansListening, setAnsListening] = useState([])
  const [ansReading, setAnsReading] = useState([])
  const [ansWriting, setAnsWriting] = useState([]) // for word_order: array of picked sentence, for write_character: typed string

  const timer = useTimer({ initialSeconds: 0, autoStart: false })

  useEffect(() => {
    ensureTodaySession()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const currentList = section === SECTION.listening ? listeningItems : section === SECTION.reading ? readingItems : writingItems
  const current = currentList[idx] ?? null

  const totalInSection =
    section === SECTION.listening ? listeningItems.length : section === SECTION.reading ? readingItems.length : writingItems.length

  const progressPercent = totalInSection ? Math.round(((idx + 1) / totalInSection) * 100) : 0

  function startExam() {
    cancel()
    const l = shuffle(listening).slice(0, 40)
    const r = shuffle(reading).slice(0, 30)

    const wordOrder = shuffle(writing.filter((x) => x.type === 'word_order')).slice(0, 5)
    const writeChar = shuffle(writing.filter((x) => x.type === 'write_character')).slice(0, 5)
    const w = shuffle([...wordOrder, ...writeChar]).slice(0, 10)

    setListeningItems(l)
    setReadingItems(r)
    setWritingItems(w)

    setAnsListening(Array(40).fill(null))
    setAnsReading(Array(30).fill(null))
    setAnsWriting(Array(10).fill(null))

    setIdx(0)
    setSection(SECTION.listening)
    timer.reset(35 * 60)
    timer.start()
  }

  function speakListening() {
    if (!current || section !== SECTION.listening) return
    const text =
      current.type === 'true_false'
        ? current.text_zh
        : current.type === 'picture_description'
          ? current.description_zh
          : current.dialogue_zh
    speak(String(text).replaceAll('\n', ' '), { lang: 'zh-CN', rate: 1.0 })
  }

  function setAnswer(val) {
    if (section === SECTION.listening) {
      setAnsListening((prev) => {
        const next = [...prev]
        next[idx] = val
        return next
      })
    } else if (section === SECTION.reading) {
      setAnsReading((prev) => {
        const next = [...prev]
        next[idx] = val
        return next
      })
    } else if (section === SECTION.writing) {
      setAnsWriting((prev) => {
        const next = [...prev]
        next[idx] = val
        return next
      })
    }
  }

  function goNext() {
    cancel()
    const nextIdx = idx + 1
    if (nextIdx < currentList.length) {
      setIdx(nextIdx)
      return
    }
    // section finished
    if (section === SECTION.listening) {
      setSection(SECTION.reading)
      setIdx(0)
      timer.reset(30 * 60)
      timer.start()
      return
    }
    if (section === SECTION.reading) {
      setSection(SECTION.writing)
      setIdx(0)
      timer.reset(15 * 60)
      timer.start()
      return
    }
    if (section === SECTION.writing) {
      timer.stop()
      setSection(SECTION.done)
      return
    }
  }

  // Auto-advance section when timer ends
  useEffect(() => {
    if (section === SECTION.intro || section === SECTION.done) return
    if (timer.secondsLeft !== 0) return
    goNext() // finish current question and section flow
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timer.secondsLeft])

  const results = useMemo(() => {
    if (section !== SECTION.done) return null

    const listeningCorrect = listeningItems.reduce((s, q, i) => {
      const a = ansListening[i]
      if (a == null) return s
      if (q.type === 'true_false') return s + (Boolean(a) === Boolean(q.answer) ? 1 : 0)
      return s + (Number(a) === Number(q.answer) ? 1 : 0)
    }, 0)

    const readingCorrect = readingItems.reduce((s, q, i) => {
      const a = ansReading[i]
      if (a == null) return s
      return s + (Number(a) === Number(q.answer) ? 1 : 0)
    }, 0)

    const writingCorrect = writingItems.reduce((s, q, i) => {
      const a = ansWriting[i]
      if (a == null) return s
      if (q.type === 'word_order') return s + (String(a) === String(q.answer) ? 1 : 0)
      if (q.type === 'write_character') return s + (String(a).trim() === String(q.answer).trim() ? 1 : 0)
      return s
    }, 0)

    return {
      date: todayISO(),
      listening: pct(listeningCorrect, listeningItems.length),
      reading: pct(readingCorrect, readingItems.length),
      writing: pct(writingCorrect, writingItems.length),
      raw: {
        listeningCorrect,
        readingCorrect,
        writingCorrect,
        listeningTotal: listeningItems.length,
        readingTotal: readingItems.length,
        writingTotal: writingItems.length,
      },
    }
  }, [ansListening, ansReading, ansWriting, listeningItems, readingItems, section, writingItems])

  useEffect(() => {
    if (section !== SECTION.done) return
    if (!results) return
    addExamResult({ date: results.date, listening: results.listening, reading: results.reading, writing: results.writing })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [section])

  return (
    <div className={styles.wrap}>
      <div className={styles.row}>
        <div>
          <div className={styles.title}>Полный тест (Mock Exam)</div>
          <div className={styles.meta}>Секции идут подряд. Вернуться к предыдущей секции нельзя.</div>
        </div>
      </div>

      {section === SECTION.intro ? (
        <Card className={styles.card}>
          <div className={styles.block}>
            <div className={styles.badgeRow}>
              <span className={styles.badge}>Аудирование: 40</span>
              <span className={styles.badge}>Чтение: 30</span>
              <span className={styles.badge}>Письмо: 10</span>
            </div>
            <div className={styles.hiddenText}>
              Во время аудирования текст скрыт до ответа. Таймеры: 35 / 30 / 15 минут. Если время секции закончится,
              приложение автоматически перейдёт дальше.
            </div>
            <div className={styles.nav}>
              <Button type="button" variant="primary" onClick={startExam}>
                Начать экзамен
              </Button>
            </div>
          </div>
        </Card>
      ) : null}

      {section !== SECTION.intro && section !== SECTION.done ? (
        <Card className={styles.card}>
          <div className={styles.row}>
            <div className={styles.badgeRow}>
              <span className={styles.badge}>
                Секция:{' '}
                {section === SECTION.listening ? 'Аудирование' : section === SECTION.reading ? 'Чтение' : 'Письмо'}
              </span>
              <span className={styles.badgeSoft}>
                Вопрос {idx + 1} / {totalInSection}
              </span>
            </div>
            <div className={styles.timer}>⏱ {timer.mmss}</div>
          </div>

          <div className={styles.progressBar} aria-label="Прогресс секции">
            <div className={styles.progressFill} style={{ width: `${progressPercent}%` }} />
          </div>

          {section === SECTION.listening ? (
            <ListeningQuestion
              q={current}
              a={ansListening[idx]}
              onAnswer={setAnswer}
              onNext={goNext}
              onSpeak={speakListening}
              ttsAvailable={ttsAvailable}
            />
          ) : null}

          {section === SECTION.reading ? (
            <ReadingQuestion q={current} a={ansReading[idx]} onAnswer={setAnswer} onNext={goNext} />
          ) : null}

          {section === SECTION.writing ? (
            <WritingQuestion q={current} a={ansWriting[idx]} onAnswer={setAnswer} onNext={goNext} />
          ) : null}
        </Card>
      ) : null}

      {section === SECTION.done && results ? (
        <Card className={styles.card}>
          <div className={styles.results}>
            <div className={styles.badgeRow}>
              <span className={styles.badge}>Результат сохранён: {results.date}</span>
            </div>

            <div className={styles.resultGrid}>
              <div className={styles.resultCard}>
                <div className={styles.resultTitle}>Аудирование</div>
                <div className={styles.resultValue}>{results.listening}%</div>
                <div className={styles.resultSub}>
                  {results.raw.listeningCorrect}/{results.raw.listeningTotal}
                </div>
              </div>
              <div className={styles.resultCard}>
                <div className={styles.resultTitle}>Чтение</div>
                <div className={styles.resultValue}>{results.reading}%</div>
                <div className={styles.resultSub}>
                  {results.raw.readingCorrect}/{results.raw.readingTotal}
                </div>
              </div>
              <div className={styles.resultCard}>
                <div className={styles.resultTitle}>Письмо</div>
                <div className={styles.resultValue}>{results.writing}%</div>
                <div className={styles.resultSub}>
                  {results.raw.writingCorrect}/{results.raw.writingTotal}
                </div>
              </div>
            </div>

            <div className={styles.nav}>
              <Button
                type="button"
                variant="primary"
                onClick={() => {
                  setSection(SECTION.intro)
                  setIdx(0)
                }}
              >
                Пройти ещё раз
              </Button>
            </div>

            <div className={styles.review}>
              <div className={styles.badgeRow}>
                <span className={styles.badge}>Разбор ошибок</span>
              </div>
              <ReviewList
                listeningItems={listeningItems}
                readingItems={readingItems}
                writingItems={writingItems}
                ansListening={ansListening}
                ansReading={ansReading}
                ansWriting={ansWriting}
              />
            </div>
          </div>
        </Card>
      ) : null}
    </div>
  )
}

function ListeningQuestion({ q, a, onAnswer, onNext, onSpeak, ttsAvailable }) {
  if (!q) return null
  const answered = a != null
  const correctLabel =
    q.type === 'true_false'
      ? Boolean(q.answer)
        ? '对 / Верно'
        : '错 / Неверно'
      : `${String.fromCharCode(65 + Number(q.answer))}. ${q.options_zh?.[Number(q.answer)] ?? ''}`

  return (
    <div className={styles.block}>
      <div className={styles.row}>
        <div className={styles.badgeRow}>
          <span className={styles.badgeSoft}>Текст скрыт до ответа</span>
        </div>
        <div className={styles.badgeRow}>
          <TTSButton onSpeak={onSpeak} disabled={!ttsAvailable} title="Прослушать" />
        </div>
      </div>

      {q.type === 'true_false' ? (
        <>
          <div className={styles.prompt}>{q.statement_zh}</div>
          <div className={styles.subRu}>{q.statement_ru}</div>
          <div className={styles.options}>
            <Option
              prefix="A."
              zh="对"
              ru="Верно"
              selected={a === true}
              disabled={answered}
              onClick={() => onAnswer(true)}
            />
            <Option
              prefix="B."
              zh="错"
              ru="Неверно"
              selected={a === false}
              disabled={answered}
              onClick={() => onAnswer(false)}
            />
          </div>
        </>
      ) : (
        <>
          <div className={styles.prompt}>{q.question_zh}</div>
          <div className={styles.subRu}>{q.question_ru}</div>
          <div className={styles.options}>
            {q.options_zh.map((zh, i) => (
              <Option
                key={i}
                prefix={`${String.fromCharCode(65 + i)}.`}
                zh={zh}
                ru={q.options_ru?.[i]}
                selected={Number(a) === i}
                disabled={answered}
                onClick={() => onAnswer(i)}
              />
            ))}
          </div>
        </>
      )}

      {!answered ? <div className={styles.hiddenText}>После выбора ответа появится текст задания.</div> : null}

      {answered ? (
        <div className={styles.reveal}>
          <div>
            Правильный ответ: <b>{correctLabel}</b>
          </div>
          {q.type === 'true_false' ? (
            <>
              <div className={styles.prompt}>{q.text_zh}</div>
              <pre className={styles.pinyin}>{q.text_pinyin}</pre>
            </>
          ) : q.type === 'picture_description' ? (
            <>
              <div className={styles.prompt}>{q.description_zh}</div>
              <pre className={styles.pinyin}>{q.description_pinyin}</pre>
            </>
          ) : (
            <>
              <pre className={styles.dialogue}>{q.dialogue_zh}</pre>
              <pre className={styles.pinyin}>{q.dialogue_pinyin}</pre>
            </>
          )}
        </div>
      ) : null}

      <div className={styles.nav}>
        <span className={styles.meta}>Назад недоступен в режиме экзамена.</span>
        <Button type="button" variant="primary" onClick={onNext} disabled={!answered}>
          Далее
        </Button>
      </div>
    </div>
  )
}

function ReadingQuestion({ q, a, onAnswer, onNext }) {
  if (!q) return null
  const answered = a != null
  return (
    <div className={styles.block}>
      {q.type === 'reading_comprehension' ? <div className={styles.textBox}>{q.text_zh}</div> : null}
      <div className={styles.prompt}>
        {q.type === 'match_response' ? q.statement : q.type === 'insert_sentence' ? q.text_with_blank : q.question_zh}
      </div>

      <div className={styles.options}>
        {(q.type === 'reading_comprehension' ? q.options_zh : q.options).map((opt, i) => (
          <Option
            key={i}
            prefix={`${String.fromCharCode(65 + i)}.`}
            zh={opt}
            ru={q.type === 'reading_comprehension' ? q.options_ru?.[i] : null}
            selected={Number(a) === i}
            disabled={answered}
            onClick={() => onAnswer(i)}
          />
        ))}
      </div>

      {answered ? (
        <div className={styles.reveal}>
          <div>
            Правильный ответ: <b>{`${String.fromCharCode(65 + Number(q.answer))}.`}</b>
          </div>
          {q.explanation_ru ? <div className={styles.subRu}>{q.explanation_ru}</div> : null}
        </div>
      ) : null}

      <div className={styles.nav}>
        <span className={styles.meta}>Назад недоступен в режиме экзамена.</span>
        <Button type="button" variant="primary" onClick={onNext} disabled={!answered}>
          Далее
        </Button>
      </div>
    </div>
  )
}

function WritingQuestion({ q, a, onAnswer, onNext }) {
  if (!q) return null
  if (q.type === 'word_order') return <WritingWordOrderQuestion q={q} a={a} onAnswer={onAnswer} onNext={onNext} />
  return <WritingCharQuestion q={q} a={a} onAnswer={onAnswer} onNext={onNext} />
}

function WritingWordOrderQuestion({ q, a, onAnswer, onNext }) {
  const [picked, setPicked] = useState([])
  const [remaining, setRemaining] = useState(() => q.words ?? [])

  const answered = a != null
  const sentence = picked.join('') + (picked.length ? '。' : '')

  function pickWord(w, i) {
    if (answered) return
    setPicked((p) => [...p, w])
    setRemaining((r) => r.filter((_, idx) => idx !== i))
  }

  function undoWord(w, i) {
    if (answered) return
    setRemaining((r) => [w, ...r])
    setPicked((p) => p.filter((_, idx) => idx !== i))
  }

  function submit() {
    if (answered) return
    const final = picked.join('') + '。'
    onAnswer(final)
  }

  return (
    <div className={styles.block}>
      <div className={styles.subRu}>{q.translation}</div>
      <div className={styles.reveal}>
        <div className={styles.prompt}>{picked.length ? picked.join('') : 'Соберите предложение'}</div>
        {picked.length ? <div className={styles.subRu}>Ваш ответ: {sentence}</div> : null}
      </div>

      <div className={styles.options}>
        {picked.map((w, i) => (
          <button
            key={`${w}-${i}`}
            type="button"
            className={`${styles.option} ${styles.selected}`}
            onClick={() => undoWord(w, i)}
          >
            <div className={styles.optMainRow}>
              <span className={styles.optZh}>{w}</span>
            </div>
            <div className={styles.optRu}>нажмите, чтобы убрать</div>
          </button>
        ))}
        {remaining.map((w, i) => (
          <button key={`${w}-${i}`} type="button" className={styles.option} onClick={() => pickWord(w, i)}>
            <div className={styles.optMainRow}>
              <span className={styles.optZh}>{w}</span>
            </div>
            <div className={styles.optRu}>нажмите, чтобы добавить</div>
          </button>
        ))}
      </div>

      {answered ? (
        <div className={styles.reveal}>
          <div>
            Правильный ответ: <b>{q.answer}</b>
          </div>
        </div>
      ) : null}

      <div className={styles.nav}>
        {!answered ? (
          <Button type="button" variant="primary" onClick={submit} disabled={picked.length === 0}>
            Сдать ответ
          </Button>
        ) : (
          <span className={styles.meta}>Назад недоступен в режиме экзамена.</span>
        )}
        <Button type="button" variant="primary" onClick={onNext} disabled={!answered}>
          Далее
        </Button>
      </div>
    </div>
  )
}

function WritingCharQuestion({ q, a, onAnswer, onNext }) {
  const answered = a != null && a !== ''
  const [val, setVal] = useState(() => (a == null ? '' : String(a)))

  function submit() {
    if (!val.trim()) return
    onAnswer(val.trim())
  }

  return (
    <div className={styles.block}>
      <div className={styles.prompt}>{q.sentence_with_pinyin}</div>
      <div className={styles.subRu}>
        Пиньинь пропуска: <b>{q.blank_pinyin}</b>
      </div>
      <div className={styles.inputRow}>
        <input
          className={styles.charInput}
          value={val}
          onChange={(e) => setVal(e.target.value)}
          disabled={a != null}
        />
        <Button type="button" variant="primary" onClick={submit} disabled={a != null || !val.trim()}>
          Сдать ответ
        </Button>
      </div>
      {a != null ? (
        <div className={styles.reveal}>
          <div>
            Правильный ответ: <b>{q.answer}</b>
          </div>
        </div>
      ) : null}
      <div className={styles.nav}>
        <span className={styles.meta}>Назад недоступен в режиме экзамена.</span>
        <Button type="button" variant="primary" onClick={onNext} disabled={!answered}>
          Далее
        </Button>
      </div>
    </div>
  )
}

function Option({ prefix, zh, ru, selected, disabled, onClick }) {
  const cls = [styles.option, selected ? styles.selected : ''].filter(Boolean).join(' ')
  return (
    <button type="button" className={cls} disabled={disabled} onClick={onClick}>
      <div className={styles.optMainRow}>
        <span className={styles.optPrefix}>{prefix}</span>
        <span className={styles.optZh}>{zh}</span>
      </div>
      {ru ? <div className={styles.optRu}>{ru}</div> : null}
    </button>
  )
}

function ReviewList({ listeningItems, readingItems, writingItems, ansListening, ansReading, ansWriting }) {
  const wrongListening = listeningItems
    .map((q, i) => ({ q, i, a: ansListening[i] }))
    .filter(({ q, a }) => {
      if (a == null) return true
      if (q.type === 'true_false') return Boolean(a) !== Boolean(q.answer)
      return Number(a) !== Number(q.answer)
    })
  const wrongReading = readingItems
    .map((q, i) => ({ q, i, a: ansReading[i] }))
    .filter(({ q, a }) => a == null || Number(a) !== Number(q.answer))
  const wrongWriting = writingItems
    .map((q, i) => ({ q, i, a: ansWriting[i] }))
    .filter(({ q, a }) => {
      if (a == null) return true
      if (q.type === 'word_order') return String(a) !== String(q.answer)
      return String(a).trim() !== String(q.answer).trim()
    })

  const all = [
    ...wrongListening.map((x) => ({ ...x, section: 'Аудирование' })),
    ...wrongReading.map((x) => ({ ...x, section: 'Чтение' })),
    ...wrongWriting.map((x) => ({ ...x, section: 'Письмо' })),
  ]

  if (all.length === 0) {
    return <div className={styles.hiddenText}>Ошибок нет — отлично.</div>
  }

  return (
    <>
      {all.slice(0, 40).map(({ section, q, i, a }, k) => (
        <div key={k} className={styles.reviewItem}>
          <div className={styles.reviewTop}>
            <span className={styles.badge}>{section}</span>
            <span className={styles.wrong}>ошибка</span>
          </div>
          <div className={styles.subRu}>Ваш ответ: {a == null ? '—' : String(a)}</div>
          <div className={styles.subRu}>Правильный ответ: {q.type === 'true_false' ? String(q.answer) : String(q.answer)}</div>
          {section === 'Чтение' && q.explanation_ru ? <div className={styles.subRu}>{q.explanation_ru}</div> : null}
          {section === 'Письмо' && q.type === 'word_order' ? <div className={styles.prompt}>{q.answer}</div> : null}
        </div>
      ))}
      {all.length > 40 ? <div className={styles.hiddenText}>Показаны первые 40 ошибок из {all.length}.</div> : null}
    </>
  )
}

import { useEffect, useMemo, useState } from 'react'
import data from '../../data/reading.json'
import { Card } from '../../components/shared/Card'
import { Button } from '../../components/shared/Button'
import { useProgress } from '../../hooks/useProgress'
import { useTimer } from '../../hooks/useTimer'
import styles from './ReadingPage.module.css'

const TYPES = [
  { id: 'all', label: 'Все' },
  { id: 'match_response', label: 'Подбери ответ' },
  { id: 'insert_sentence', label: 'Вставь слово/фразу' },
  { id: 'reading_comprehension', label: 'Понимание текста' },
]

function shuffle(arr) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

export function ReadingPage() {
  const { ensureTodaySession } = useProgress()
  const [type, setType] = useState('all')
  const [order, setOrder] = useState('shuffle')
  const [timerOn, setTimerOn] = useState(false)
  const [perQuestionSec, setPerQuestionSec] = useState(90)
  const timer = useTimer({ initialSeconds: perQuestionSec, autoStart: false })

  const [idx, setIdx] = useState(0)
  const [picked, setPicked] = useState(null) // null | { value, ok }

  useEffect(() => {
    ensureTodaySession()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const list = useMemo(() => {
    const base = type === 'all' ? data : data.filter((x) => x.type === type)
    return order === 'shuffle' ? shuffle(base) : base
  }, [order, type])

  const current = list[idx] ?? null

  useEffect(() => {
    setIdx(0)
    setPicked(null)
  }, [type, order])

  useEffect(() => {
    setPicked(null)
    if (timerOn) {
      timer.reset(perQuestionSec)
      timer.start()
    } else {
      timer.stop()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [idx, timerOn, perQuestionSec])

  useEffect(() => {
    if (!timerOn) return
    if (timer.secondsLeft !== 0) return
    if (!current) return
    if (picked) return
    // Авто-сдача: считаем неверным, если время вышло
    setPicked({ value: null, ok: false, timeout: true })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timer.secondsLeft, timerOn])

  function next() {
    setPicked(null)
    setIdx((i) => (i + 1 >= list.length ? 0 : i + 1))
  }

  function prev() {
    setPicked(null)
    setIdx((i) => (i - 1 < 0 ? Math.max(0, list.length - 1) : i - 1))
  }

  function answer(i) {
    if (!current || picked) return
    const ok = Number(i) === Number(current.answer)
    setPicked({ value: i, ok })
    if (timerOn) timer.stop()
  }

  const title =
    current?.type === 'match_response'
      ? 'Подбери ответ'
      : current?.type === 'insert_sentence'
        ? 'Вставь слово/фразу'
        : current?.type === 'reading_comprehension'
          ? 'Понимание текста'
          : ''

  return (
    <div className={styles.wrap}>
      <div className={styles.top}>
        <div className={styles.titleRow}>
          <div className={styles.title}>Чтение</div>
          <div className={styles.meta}>
            Задание: <b>{Math.min(idx + 1, list.length)}</b> / <b>{list.length}</b>
          </div>
        </div>

        <Card className={styles.controls}>
          <div className={styles.row}>
            <label className={styles.label}>
              Тип
              <select className={styles.select} value={type} onChange={(e) => setType(e.target.value)}>
                {TYPES.map((t) => (
                  <option key={t.id} value={t.id}>
                    {t.label}
                  </option>
                ))}
              </select>
            </label>

            <label className={styles.label}>
              Порядок
              <select className={styles.select} value={order} onChange={(e) => setOrder(e.target.value)}>
                <option value="shuffle">Случайно</option>
                <option value="in_order">По порядку</option>
              </select>
            </label>

            <label className={styles.label}>
              Таймер
              <div className={styles.toggleRow}>
                <input type="checkbox" checked={timerOn} onChange={(e) => setTimerOn(e.target.checked)} />
                <span className={styles.toggleHint}>на вопрос</span>
              </div>
            </label>

            <label className={styles.label}>
              Время (сек)
              <input
                className={styles.input}
                type="number"
                min={20}
                max={600}
                value={perQuestionSec}
                onChange={(e) => setPerQuestionSec(Number(e.target.value))}
                disabled={!timerOn}
              />
              {timerOn ? <div className={styles.timerBadge}>Осталось: {timer.mmss}</div> : null}
            </label>
          </div>
        </Card>
      </div>

      <Card className={styles.card}>
        {!current ? (
          <div className={styles.empty}>Нет заданий для выбранного фильтра.</div>
        ) : (
          <>
            <div className={styles.cardTop}>
              <div className={styles.badges}>
                <span className={styles.badge}>{title}</span>
                {timerOn ? <span className={styles.badgeSoft}>таймер включён</span> : null}
              </div>
            </div>

            {current.type === 'match_response' ? (
              <div className={styles.block}>
                <div className={styles.prompt}>{current.statement}</div>
                <div className={styles.options}>
                  {current.options.map((opt, i) => (
                    <OptionButton
                      key={i}
                      prefix={`${String.fromCharCode(65 + i)}.`}
                      main={opt}
                      chosen={picked?.value === i}
                      ok={picked ? Number(current.answer) === i : null}
                      bad={picked ? picked.value === i && !picked.ok : null}
                      disabled={Boolean(picked)}
                      onClick={() => answer(i)}
                    />
                  ))}
                </div>
              </div>
            ) : null}

            {current.type === 'insert_sentence' ? (
              <div className={styles.block}>
                <div className={styles.prompt}>{current.text_with_blank}</div>
                <div className={styles.options}>
                  {current.options.map((opt, i) => (
                    <OptionButton
                      key={i}
                      prefix={`${String.fromCharCode(65 + i)}.`}
                      main={opt}
                      chosen={picked?.value === i}
                      ok={picked ? Number(current.answer) === i : null}
                      bad={picked ? picked.value === i && !picked.ok : null}
                      disabled={Boolean(picked)}
                      onClick={() => answer(i)}
                    />
                  ))}
                </div>
              </div>
            ) : null}

            {current.type === 'reading_comprehension' ? (
              <div className={styles.block}>
                <div className={styles.textBox}>{current.text_zh}</div>
                <div className={styles.prompt}>{current.question_zh}</div>
                <div className={styles.options}>
                  {current.options_zh.map((zh, i) => (
                    <OptionButton
                      key={i}
                      prefix={`${String.fromCharCode(65 + i)}.`}
                      main={zh}
                      sub={current.options_ru?.[i]}
                      chosen={picked?.value === i}
                      ok={picked ? Number(current.answer) === i : null}
                      bad={picked ? picked.value === i && !picked.ok : null}
                      disabled={Boolean(picked)}
                      onClick={() => answer(i)}
                    />
                  ))}
                </div>
              </div>
            ) : null}

            {picked ? (
              <div className={picked.ok ? styles.feedbackOk : styles.feedbackBad}>
                {picked.timeout ? 'Время вышло.' : picked.ok ? 'Правильно.' : 'Неправильно.'}
                <div className={styles.feedbackMeta}>
                  Правильный ответ:{' '}
                  <b>{`${String.fromCharCode(65 + Number(current.answer))}.`}</b>
                </div>
                {current.explanation_ru ? <div className={styles.expl}>{current.explanation_ru}</div> : null}
              </div>
            ) : null}

            <div className={styles.nav}>
              <Button type="button" variant="ghost" onClick={prev}>
                Назад
              </Button>
              <Button type="button" variant="primary" onClick={next}>
                Далее
              </Button>
            </div>
          </>
        )}
      </Card>
    </div>
  )
}

function OptionButton({ prefix, main, sub, chosen, ok, bad, disabled, onClick }) {
  const cls = [styles.option, chosen ? styles.optionChosen : '', ok ? styles.optionOk : '', bad ? styles.optionBad : '']
    .filter(Boolean)
    .join(' ')
  return (
    <button type="button" className={cls} disabled={disabled} onClick={onClick}>
      <div className={styles.optMainRow}>
        <span className={styles.optPrefix}>{prefix}</span>
        <span className={styles.optMain}>{main}</span>
      </div>
      {sub ? <div className={styles.optSub}>{sub}</div> : null}
    </button>
  )
}

import { useEffect, useMemo, useState } from 'react'
import wordsData from '../../data/words.json'
import { Card } from '../../components/shared/Card'
import { Button } from '../../components/shared/Button'
import { TTSButton } from '../../components/shared/TTSButton'
import { useProgress } from '../../hooks/useProgress'
import { useTTS } from '../../hooks/useTTS'
import { useSpacedRepQueue, nextWordAfterAnswer } from '../../hooks/useSpacedRep'
import { isPinyinMatch, normalizePinyin } from '../../utils/pinyin'
import styles from './VocabularyPage.module.css'

const MODES = [
  { id: 'cards', label: 'Флипкарты' },
  { id: 'quiz', label: 'Тест (перевод)' },
  { id: 'pinyin', label: 'Пиньинь' },
]

const ONLY = [
  { id: 'all', label: 'Все' },
  { id: 'learning', label: 'Изучаемые' },
  { id: 'new', label: 'Новые' },
  { id: 'known', label: 'Выученные' },
  { id: 'problem', label: 'Проблемные' },
]

function uniq(arr) {
  return Array.from(new Set(arr))
}

function choice(arr) {
  return arr[Math.floor(Math.random() * arr.length)]
}

export function VocabularyPage() {
  const { wordsProgress, setWordProgress, settings, setSettings, ensureTodaySession } = useProgress()
  const { available: ttsAvailable, speak } = useTTS()

  const [mode, setMode] = useState('cards')
  const [level, setLevel] = useState('all')
  const [topic, setTopic] = useState('all')
  const [only, setOnly] = useState('all')
  const [cardRevealed, setCardRevealed] = useState(false)
  const [idx, setIdx] = useState(0)

  // Quiz mode state
  const [quizOptions, setQuizOptions] = useState([])
  const [quizPicked, setQuizPicked] = useState(null)

  // Pinyin mode state
  const [pinyinInput, setPinyinInput] = useState('')
  const [pinyinChecked, setPinyinChecked] = useState(null) // null | { ok, expected }

  useEffect(() => {
    ensureTodaySession()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const topics = useMemo(() => ['all', ...uniq(wordsData.map((w) => w.topic).filter(Boolean))], [])

  const filteredWords = useMemo(() => {
    return wordsData.filter((w) => {
      if (level !== 'all' && String(w.hsk_level) !== String(level)) return false
      if (topic !== 'all' && w.topic !== topic) return false
      return true
    })
  }, [level, topic])

  const queue = useSpacedRepQueue(filteredWords, wordsProgress, { only })
  const current = queue[idx] ?? queue[0] ?? null
  const word = current?.word ?? null
  const progress = current?.progress ?? null

  const knownCount = useMemo(
    () => wordsData.filter((w) => (wordsProgress?.[String(w.id)]?.status ?? 'new') === 'known').length,
    [wordsProgress],
  )

  useEffect(() => {
    setIdx(0)
    setCardRevealed(false)
    setQuizPicked(null)
    setPinyinInput('')
    setPinyinChecked(null)
  }, [mode, level, topic, only])

  useEffect(() => {
    if (!word) return
    if (mode !== 'quiz') return

    const pool = filteredWords.filter((w) => w.id !== word.id && w.translation)
    const opts = [word]
    while (opts.length < 4 && pool.length > 0) {
      const w = choice(pool)
      if (!opts.some((x) => x.id === w.id)) opts.push(w)
    }
    setQuizOptions(opts.sort(() => Math.random() - 0.5))
    setQuizPicked(null)
  }, [filteredWords, mode, word])

  function speakWord() {
    if (!word) return
    speak(word.hanzi, { lang: 'zh-CN', rate: 1.0 })
  }

  function speakExample() {
    if (!word?.example_zh) return
    speak(word.example_zh, { lang: 'zh-CN', rate: 1.0 })
  }

  function goNext() {
    setCardRevealed(false)
    setQuizPicked(null)
    setPinyinInput('')
    setPinyinChecked(null)
    setIdx((i) => (i + 1 >= queue.length ? 0 : i + 1))
  }

  function markKnown() {
    if (!word) return
    setWordProgress(word.id, { status: 'known', correctStreak: 3, lastSeen: Date.now() })
    goNext()
  }

  function markLearningWrong() {
    if (!word) return
    const next = nextWordAfterAnswer(current, false)
    setWordProgress(word.id, { ...next, lastSeen: Date.now() })
    goNext()
  }

  function markHard() {
    if (!word) return
    setWordProgress(word.id, { status: 'hard', correctStreak: 0, lastSeen: Date.now() })
    goNext()
  }

  function handleQuizPick(optIdx) {
    if (!word) return
    if (quizPicked != null) return
    const picked = quizOptions[optIdx]
    const ok = picked?.id === word.id
    setQuizPicked({ optIdx, ok })
    const next = nextWordAfterAnswer(current, ok)
    setWordProgress(word.id, { ...next, lastSeen: Date.now() })
  }

  function handlePinyinCheck() {
    if (!word) return
    if (pinyinChecked) return
    const ok = isPinyinMatch(pinyinInput, word.pinyin)
    setPinyinChecked({ ok, expected: word.pinyin })
    const next = nextWordAfterAnswer(current, ok)
    setWordProgress(word.id, { ...next, lastSeen: Date.now() })
  }

  const pinyinPosition = settings?.pinyinPosition ?? 'below'
  const togglePinyinPosition = () =>
    setSettings({ ...(settings ?? {}), pinyinPosition: pinyinPosition === 'below' ? 'above' : 'below' })

  return (
    <div className={styles.wrap}>
      <div className={styles.top}>
        <div className={styles.titleRow}>
          <div className={styles.title}>Слова</div>
          <div className={styles.meta}>
            Выучено: <b>{knownCount}</b> из <b>{wordsData.length}</b>
          </div>
        </div>

        <Card className={styles.filters}>
          <div className={styles.row}>
            <label className={styles.label}>
              Уровень
              <select className={styles.select} value={level} onChange={(e) => setLevel(e.target.value)}>
                <option value="all">Все</option>
                <option value="1">HSK 1</option>
                <option value="2">HSK 2</option>
                <option value="3">HSK 3</option>
              </select>
            </label>

            <label className={styles.label}>
              Тема
              <select className={styles.select} value={topic} onChange={(e) => setTopic(e.target.value)}>
                {topics.map((t) => (
                  <option key={t} value={t}>
                    {t === 'all' ? 'Все' : t}
                  </option>
                ))}
              </select>
            </label>

            <label className={styles.label}>
              Сессия
              <select className={styles.select} value={only} onChange={(e) => setOnly(e.target.value)}>
                {ONLY.map((o) => (
                  <option key={o.id} value={o.id}>
                    {o.label}
                  </option>
                ))}
              </select>
            </label>

            <label className={styles.label}>
              Пиньинь
              <Button type="button" variant="ghost" size="sm" onClick={togglePinyinPosition}>
                {pinyinPosition === 'below' ? 'снизу' : 'сверху'}
              </Button>
            </label>
          </div>

          <div className={styles.modeRow}>
            {MODES.map((m) => (
              <Button
                key={m.id}
                type="button"
                variant={mode === m.id ? 'primary' : 'ghost'}
                size="sm"
                onClick={() => setMode(m.id)}
              >
                {m.label}
              </Button>
            ))}
          </div>
        </Card>
      </div>

      <Card className={styles.session}>
        {!word ? (
          <div className={styles.empty}>
            Нет слов для выбранных фильтров.
            <div className={styles.emptyHint}>Попробуйте «Все» или сменить уровень/тему.</div>
          </div>
        ) : (
          <>
            <div className={styles.sessionTop}>
              <div className={styles.badges}>
                <span className={styles.badge}>HSK {word.hsk_level}</span>
                <span className={styles.badge}>{word.topic}</span>
                <span className={styles.badgeSoft}>
                  статус: <b>{progress?.status ?? 'new'}</b>
                </span>
              </div>

              <div className={styles.tts}>
                <TTSButton onSpeak={speakWord} disabled={!ttsAvailable} />
              </div>
            </div>

            {mode === 'cards' ? (
              <div className={styles.cardMode}>
                <button type="button" className={styles.cardFace} onClick={() => setCardRevealed((v) => !v)}>
                  {pinyinPosition === 'above' ? <div className="pinyin">{word.pinyin}</div> : null}
                  <div className={`hanzi ${styles.hanzi}`}>{word.hanzi}</div>
                  {pinyinPosition === 'below' ? <div className="pinyin">{word.pinyin}</div> : null}
                  <div className={styles.tapHint}>{cardRevealed ? 'нажмите, чтобы скрыть' : 'нажмите, чтобы открыть'}</div>
                </button>

                {cardRevealed ? (
                  <div className={styles.reveal}>
                    <div className={styles.translation}>{word.translation || '—'}</div>
                    {Array.isArray(word.classifiers) && word.classifiers.length > 0 ? (
                      <div className={styles.classifiers}>
                        Счётные слова: <b>{word.classifiers.join(', ')}</b>
                      </div>
                    ) : null}
                    {word.example_zh ? (
                      <div className={styles.example}>
                        <div className={styles.exampleRow}>
                          <div className={styles.exampleZh}>{word.example_zh}</div>
                          <TTSButton onSpeak={speakExample} disabled={!ttsAvailable} />
                        </div>
                        {word.example_pinyin ? <div className="pinyin">{word.example_pinyin}</div> : null}
                        {word.example_ru ? <div className={styles.exampleRu}>{word.example_ru}</div> : null}
                      </div>
                    ) : (
                      <div className={styles.exampleEmpty}>Пример пока не задан в данных.</div>
                    )}
                  </div>
                ) : null}

                <div className={styles.actions}>
                  <Button type="button" variant="good" onClick={markKnown}>
                    Знаю
                  </Button>
                  <Button type="button" variant="bad" onClick={markLearningWrong}>
                    Не знаю
                  </Button>
                  <Button type="button" variant="ghost" onClick={markHard}>
                    Сложное
                  </Button>
                  <Button type="button" variant="ghost" onClick={goNext}>
                    Далее
                  </Button>
                </div>
              </div>
            ) : null}

            {mode === 'quiz' ? (
              <div className={styles.quizMode}>
                <div className={styles.prompt}>
                  {pinyinPosition === 'above' ? <div className="pinyin">{word.pinyin}</div> : null}
                  <div className={`hanzi ${styles.hanzi}`}>{word.hanzi}</div>
                  {pinyinPosition === 'below' ? <div className="pinyin">{word.pinyin}</div> : null}
                  <div className={styles.promptSub}>Выберите правильный перевод</div>
                </div>

                <div className={styles.options}>
                  {quizOptions.map((o, i) => {
                    const picked = quizPicked?.optIdx === i
                    const ok = quizPicked && o.id === word.id
                    const bad = quizPicked && picked && !quizPicked.ok
                    return (
                      <button
                        key={o.id}
                        type="button"
                        className={[
                          styles.option,
                          quizPicked ? styles.optionLocked : '',
                          ok ? styles.optionOk : '',
                          bad ? styles.optionBad : '',
                        ]
                          .filter(Boolean)
                          .join(' ')}
                        onClick={() => handleQuizPick(i)}
                        disabled={quizPicked != null}
                      >
                        {o.translation || '—'}
                      </button>
                    )
                  })}
                </div>

                <div className={styles.actions}>
                  <Button type="button" variant="ghost" onClick={markHard}>
                    Сложное
                  </Button>
                  <Button type="button" variant="primary" onClick={goNext} disabled={quizPicked == null}>
                    Далее
                  </Button>
                </div>
              </div>
            ) : null}

            {mode === 'pinyin' ? (
              <div className={styles.pinyinMode}>
                <div className={styles.prompt}>
                  <div className={`hanzi ${styles.hanzi}`}>{word.hanzi}</div>
                  <div className={styles.promptSub}>Введите пиньинь</div>
                </div>

                <div className={styles.pinyinRow}>
                  <input
                    className={styles.pinyinInput}
                    value={pinyinInput}
                    onChange={(e) => setPinyinInput(e.target.value)}
                    placeholder="например: yīnwèi"
                    inputMode="text"
                    autoCapitalize="none"
                    autoCorrect="off"
                    spellCheck={false}
                    disabled={pinyinChecked != null}
                  />
                  <Button type="button" variant="primary" onClick={handlePinyinCheck} disabled={!pinyinInput.trim() || pinyinChecked != null}>
                    Проверить
                  </Button>
                </div>

                {pinyinChecked ? (
                  <div className={pinyinChecked.ok ? styles.feedbackOk : styles.feedbackBad}>
                    {pinyinChecked.ok ? (
                      <>Правильно.</>
                    ) : (
                      <>
                        Неправильно. Правильный пиньинь: <b>{pinyinChecked.expected}</b>
                      </>
                    )}
                    <div className={styles.feedbackMeta}>
                      Ваш ответ: <code className={styles.code}>{normalizePinyin(pinyinInput) || '—'}</code>
                    </div>
                  </div>
                ) : null}

                <div className={styles.actions}>
                  <Button type="button" variant="ghost" onClick={markHard}>
                    Сложное
                  </Button>
                  <Button type="button" variant="primary" onClick={goNext} disabled={!pinyinChecked}>
                    Далее
                  </Button>
                </div>
              </div>
            ) : null}
          </>
        )}
      </Card>
    </div>
  )
}

import { useEffect, useMemo, useState } from 'react'
import data from '../../data/writing.json'
import { Card } from '../../components/shared/Card'
import { Button } from '../../components/shared/Button'
import { useProgress } from '../../hooks/useProgress'
import styles from './WritingPage.module.css'

const TYPES = [
  { id: 'all', label: 'Все' },
  { id: 'word_order', label: 'Часть A: порядок слов' },
  { id: 'write_character', label: 'Часть B: впиши иероглиф' },
]

function shuffle(arr) {
  const a = [...arr]
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[a[i], a[j]] = [a[j], a[i]]
  }
  return a
}

export function WritingPage() {
  const { ensureTodaySession } = useProgress()
  const [type, setType] = useState('all')
  const [order, setOrder] = useState('shuffle')
  const [idx, setIdx] = useState(0)

  useEffect(() => {
    ensureTodaySession()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const list = useMemo(() => {
    const base = type === 'all' ? data : data.filter((x) => x.type === type)
    return order === 'shuffle' ? shuffle(base) : base
  }, [order, type])

  const current = list[idx] ?? null

  useEffect(() => {
    setIdx(0)
  }, [type, order])

  function next() {
    setIdx((i) => (i + 1 >= list.length ? 0 : i + 1))
  }

  function prev() {
    setIdx((i) => (i - 1 < 0 ? Math.max(0, list.length - 1) : i - 1))
  }

  const title = current?.type === 'word_order' ? 'Часть A: порядок слов' : 'Часть B: впиши иероглиф'

  return (
    <div className={styles.wrap}>
      <div className={styles.top}>
        <div className={styles.titleRow}>
          <div className={styles.title}>Письмо</div>
          <div className={styles.meta}>
            Задание: <b>{Math.min(idx + 1, list.length)}</b> / <b>{list.length}</b>
          </div>
        </div>

        <Card className={styles.controls}>
          <div className={styles.row}>
            <label className={styles.label}>
              Тип
              <select className={styles.select} value={type} onChange={(e) => setType(e.target.value)}>
                {TYPES.map((t) => (
                  <option key={t.id} value={t.id}>
                    {t.label}
                  </option>
                ))}
              </select>
            </label>

            <label className={styles.label}>
              Порядок
              <select className={styles.select} value={order} onChange={(e) => setOrder(e.target.value)}>
                <option value="shuffle">Случайно</option>
                <option value="in_order">По порядку</option>
              </select>
            </label>

            <div className={styles.hintBox}>
              <div className={styles.hintTitle}>Подсказка</div>
              <div className={styles.hintText}>
                A: соберите предложение кликами. B: впишите иероглиф по пиньиню.
              </div>
            </div>
          </div>
        </Card>
      </div>

      <Card className={styles.card}>
        {!current ? (
          <div className={styles.empty}>Нет заданий для выбранного фильтра.</div>
        ) : (
          <>
            <div className={styles.cardTop}>
              <div className={styles.badges}>
                <span className={styles.badge}>{title}</span>
              </div>
            </div>

            {current.type === 'word_order' ? <WordOrderExercise ex={current} /> : <WriteCharacterExercise ex={current} />}

            <div className={styles.nav}>
              <Button type="button" variant="ghost" onClick={prev}>
                Назад
              </Button>
              <Button type="button" variant="primary" onClick={next}>
                Далее
              </Button>
            </div>
          </>
        )}
      </Card>
    </div>
  )
}

function WordOrderExercise({ ex }) {
  const [picked, setPicked] = useState([])
  const [remaining, setRemaining] = useState(() => ex.words ?? [])
  const [checked, setChecked] = useState(null) // null | { ok }

  const sentence = picked.join('')

  function pickWord(w, idx) {
    if (checked) return
    setPicked((p) => [...p, w])
    setRemaining((r) => r.filter((_, i) => i !== idx))
  }

  function undoWord(w, idx) {
    if (checked) return
    setRemaining((r) => {
      const next = [...r]
      next.splice(0, 0, w)
      return next
    })
    setPicked((p) => p.filter((_, i) => i !== idx))
  }

  function reset() {
    setPicked([])
    setRemaining(ex.words ?? [])
    setChecked(null)
  }

  function check() {
    setChecked({ ok: sentence === ex.answer })
  }

  return (
    <div className={styles.block}>
      <div className={styles.promptTitle}>Составь предложение</div>
      <div className={styles.translation}>{ex.translation}</div>

      <div className={styles.builder}>
        {picked.length === 0 ? <span className={styles.builderHint}>Нажимайте слова ниже</span> : null}
        {picked.map((w, i) => (
          <button key={`${w}-${i}`} type="button" className={styles.chipPicked} onClick={() => undoWord(w, i)}>
            {w}
          </button>
        ))}
      </div>

      <div className={styles.hints}>
        {remaining.map((w, i) => (
          <button key={`${w}-${i}`} type="button" className={styles.chip} onClick={() => pickWord(w, i)}>
            {w}
          </button>
        ))}
      </div>

      {checked ? (
        <div className={checked.ok ? styles.feedbackOk : styles.feedbackBad}>
          {checked.ok ? (
            'Правильно.'
          ) : (
            <>
              Неправильно. Ответ: <b>{ex.answer}</b>
            </>
          )}
        </div>
      ) : null}

      <div className={styles.actions}>
        <Button type="button" variant="primary" onClick={check} disabled={picked.length === 0}>
          Проверить
        </Button>
        <Button type="button" variant="ghost" onClick={reset}>
          Сброс
        </Button>
      </div>
    </div>
  )
}

function WriteCharacterExercise({ ex }) {
  const [value, setValue] = useState('')
  const [checked, setChecked] = useState(null) // null | { ok }
  const [showHint, setShowHint] = useState(false)
  const [showAnswer, setShowAnswer] = useState(false)

  function check() {
    const ok = String(value).trim() === String(ex.answer).trim()
    setChecked({ ok })
  }

  function reset() {
    setValue('')
    setChecked(null)
    setShowHint(false)
    setShowAnswer(false)
  }

  return (
    <div className={styles.block}>
      <div className={styles.promptTitle}>Впиши иероглиф</div>
      <div className={styles.sentencePinyin}>{ex.sentence_with_pinyin}</div>
      <div className={styles.sub}>
        Пиньинь пропуска: <b>{ex.blank_pinyin}</b>
      </div>

      <div className={styles.inputRow}>
        <input
          className={styles.charInput}
          value={value}
          onChange={(e) => setValue(e.target.value)}
          placeholder="впишите иероглиф(ы)…"
          inputMode="text"
          autoCapitalize="none"
          autoCorrect="off"
          spellCheck={false}
          disabled={checked?.ok === true}
        />
        <Button type="button" variant="primary" onClick={check} disabled={!value.trim() || checked != null}>
          Проверить
        </Button>
      </div>

      {checked ? (
        <div className={checked.ok ? styles.feedbackOk : styles.feedbackBad}>
          {checked.ok ? 'Правильно.' : 'Неправильно.'}
          {!checked.ok ? (
            <div className={styles.feedbackMeta}>
              Правильный ответ: <b>{ex.answer}</b>
            </div>
          ) : null}
        </div>
      ) : null}

      <div className={styles.actions}>
        <Button type="button" size="sm" variant="ghost" onClick={() => setShowHint((v) => !v)}>
          {showHint ? 'Скрыть подсказку' : 'Показать подсказку'}
        </Button>
        <Button type="button" size="sm" variant="ghost" onClick={() => setShowAnswer((v) => !v)}>
          {showAnswer ? 'Скрыть ответ' : 'Показать ответ'}
        </Button>
        <Button type="button" size="sm" variant="ghost" onClick={reset}>
          Сброс
        </Button>
      </div>

      {showHint ? (
        <div className={styles.hintPanel}>
          <div className={styles.hintTitle2}>Подсказка (черты/образ)</div>
          <div className={styles.hintChar}>{ex.stroke_order_hint || ex.answer}</div>
          <div className={styles.hintText2}>
            Сейчас это минимальная подсказка. Если хочешь, добавлю офлайн‑SVG порядка черт (stroke order) для top‑30.
          </div>
        </div>
      ) : null}

      {showAnswer ? (
        <div className={styles.answerPanel}>
          Ответ: <b className={styles.answerBig}>{ex.answer}</b>
        </div>
      ) : null}
    </div>
  )
}
